// prometheus/prometheus/util/pool/pool.go (excerpt)
// Buckets uses sync.Pool internally to recycle []byte buffers across
// scrape-and-parse cycles, reducing GC churn during ingestion bursts.
type Pool struct {
	buckets []sync.Pool
	sizes   []int
	make    func(int) interface{}
}

func (p *Pool) Get(sz int) interface{} {
	for i, bktSize := range p.sizes {
		if sz > bktSize {
			continue
		}
		b := p.buckets[i].Get()
		if b == nil {
			b = p.make(bktSize)
		}
		return b
	}
	return p.make(sz)
}

